using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Fix 1: Discriminator property renamed from "Discriminator" to "$type" in EF 9.
            // Keep old name so existing documents are still found.
            b.HasDiscriminator<string>("Discriminator");

            // Fix 2: id format changed from "Blog|1" to just "1" in EF 9.
            // Keep old format so existing documents are still addressable.
            b.HasDiscriminatorInJsonId();

            // Fix 3: HasIndex now throws on Cosmos (was silently ignored).
            // REMOVED: b.HasIndex(b => b.Name);
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

